}

package main.rice.obj;

/**
 * Abstract base class for all iterable Python objects.
 *
 * @param <T> the type of the underlying Java collection
 * @param <E> the element type (must extend APyObj)
 */
public abstract class AIterablePyObj<T, E extends APyObj<?>> extends APyObj<T> {
}

package main.rice.obj;

import java.util.ArrayList;
import java.util.List;
import java.util.stream.Collectors;

/**
 * Represents a Python string object, stored internally as a list of PyCharObj.
 */
public class PyStringObj extends AIterablePyObj<List<PyCharObj>, PyCharObj> {

    public PyStringObj(String str) {
        this.value = new ArrayList<>();
        for (char c : str.toCharArray()) {
            this.value.add(new PyCharObj(c));
        }
    }

    @Override
    public String toString() {
        return "'" + value.stream()
            .map(c -> String.valueOf(c.getValue()))
            .collect(Collectors.joining()) + "'";
    }
}

