package main.rice.obj;

import java.util.Set;
import java.util.stream.Collectors;

/**
 * Represents a Python set object.
 *
 * @param <E> the element type
 */
public class PySetObj<E extends APyObj<?>> extends AIterablePyObj<Set<E>, E> {

    public PySetObj(Set<E> value) {
        this.value = value;
    }

    @Override
    public String toString() {
        if (value.isEmpty()) {
            return "set()";
        }
        return "{" + value.stream()
            .map(Object::toString)
            .collect(Collectors.joining(", ")) + "}";
    }
}

package main.rice.obj;

/**
 * Represents a Python boolean object (True/False).
 */
public class PyBoolObj extends APyObj<Boolean> {

    public PyBoolObj(Boolean value) {
        this.value = value;
    }

    @Override
    public String toString() {
        return value ? "True" : "False";
    }
}

package main.rice.obj;

import java.util.List;
import java.util.stream.Collectors;

/**
 * Represents a Python tuple object.
 *
 * @param <E> the element type
 */
public class PyTupleObj<E extends APyObj<?>> extends AIterablePyObj<List<E>, E> {

    public PyTupleObj(List<E> value) {
        this.value = value;
    }

    @Override
    public String toString() {
        if (value.size() == 1) {
            return "(" + value.get(0).toString() + ",)";
        }
        return "(" + value.stream()
            .map(Object::toString)
            .collect(Collectors.joining(", ")) + ")";
    }
}

package main.rice.obj;

/**
 * Represents a Python character object (single character string in Python).
 */
public class PyCharObj extends APyObj<Character> {

    public PyCharObj(Character value) {
        this.value = value;
    }

    @Override
    public String toString() {
        return "'" + value + "'";
    }
}

package main.rice.obj;

import java.util.Map;
import java.util.stream.Collectors;

/**
 * Represents a Python dictionary object.
 *
 * @param <K> the key type
 * @param <V> the value type
 */
public class PyDictObj<K extends APyObj<?>, V extends APyObj<?>> extends APyObj<Map<K, V>> {

    public PyDictObj(Map<K, V> value) {
        this.value = value;
    }

    @Override
    public String toString() {
        if (value.isEmpty()) {
            return "{}";
        }
        return "{" + value.entrySet().stream()
            .map(e -> e.getKey().toString() + ": " + e.getValue().toString())
            .collect(Collectors.joining(", ")) + "}";
    }
}

